def _truncate_uploaded_source_snippet(text: Any, *, max_chars: int = 160) -> str:
    raw = str(text or "").strip()
    if not raw:
        return ""
    collapsed = re.sub(r"\s+", " ", raw)
    if len(collapsed) <= max_chars:
        return collapsed
    return f"{collapsed[: max_chars - 3].rstrip()}..."


def _build_uploaded_file_document_citations(
    current_chat_history,
    *,
    context_type: str = None,
    limit: int = 8,
) -> List[Dict[str, Any]]:
    if context_type == "pipeline":
        return []
    if not isinstance(current_chat_history, list):
        return []

    citations: List[Dict[str, Any]] = []
    seen_keys = set()

    for message in current_chat_history:
        if not isinstance(message, dict):
            continue
        if str(message.get("display_type") or "").strip() != "file_icon":
            continue

        tool_data = message.get("tool_data")
        if not isinstance(tool_data, dict):
            continue

        extracted_text = str(tool_data.get("text") or "").strip()
        if not extracted_text:
            continue

        doc_id = str(
            tool_data.get("analysis_file_id")
            or tool_data.get("file_id")
            or ""
        ).strip()
        filename = str(
            tool_data.get("filename")
            or tool_data.get("stored_filename")
            or tool_data.get("original_filename")
            or tool_data.get("display_name")
            or tool_data.get("displayName")
            or ""
        ).strip()
        label = filename or doc_id
        if not label:
            continue

        dedupe_key = (doc_id or label).strip().lower()
        if not dedupe_key or dedupe_key in seen_keys:
            continue
        seen_keys.add(dedupe_key)

        citations.append(
            {
                "citation_id": f"U{len(citations) + 1}",
                "doc_id": doc_id or label,
                "filename": filename or None,
                "label": label,
                "page_hint": None,
                "snippet": _truncate_uploaded_source_snippet(extracted_text),
                "source_type": "user_file",
                "guideline_name": None,
                "document_path": None,
                "is_resolvable": True,
            }
        )
        if len(citations) >= limit:
            break

    return citations


def _extract_guideline_document_citations(context_details, *, limit: int = 64) -> List[Dict[str, Any]]:
    if not isinstance(context_details, dict):
        return []

    retrieval = context_details.get("retrieval")
    if not isinstance(retrieval, dict):
        return []

    raw_citations = retrieval.get("document_citations")
    if not isinstance(raw_citations, list):
        return []

    citations: List[Dict[str, Any]] = []
    for row in raw_citations:
        if not isinstance(row, dict):
            continue
        citations.append(dict(row))
        if len(citations) >= limit:
            break
    return citations


